mapper.insert:
MERGE INTO NF_CNNCTN_TRADINFO_MGT X
USING (

		SELECT COUNT(*) COUNT 
		FROM NF_CNNCTN_TRADINFO_MGT 
		WHERE TRAD_NO = #{tradNo} AND CNNCTN_TRAD_NO = #{cnnctnTradNo}
) Y 
ON (
	Y.COUNT > 0
	AND X.TRAD_NO = #{tradNo}
	AND X.CNNCTN_TRAD_NO = #{cnnctnTradNo}
)
WHEN MATCHED THEN 
	UPDATE SET 
		X.LST_CHNG_DT = CURRENT TIMESTAMP,
		X.CNNCTN_TRAD_NO = #{cnnctnTradNo}

			,CNNCTN_WAY = #{cnnctnWayDynamic}


			,X.CNNCTN_SIGN_ID = #{cnnctnSignId}

WHEN NOT MATCHED THEN 
	INSERT( 
			X.CNNCTN_WAY,
			X.TRAD_NO,
			X.CNNCTN_TRAD_NO,
			X.CNNCTN_SND_YN,
			X.LST_CHNG_DT,
			X.INIT_REGIST_DT

			,X.CNNCTN_LOAN_LMT_AMT


			,X.CNNCTN_SIGN_ID

	) VALUES (
			#{cnnctnWay},
			#{tradNo}, 
			#{cnnctnTradNo},
			'N',
			CURRENT TIMESTAMP,
			CURRENT TIMESTAMP

			,#{cnnctnLoanLmtAmt}


			,#{cnnctnSignId}

	)
